/**
 * @summary List invites for a team
 */
export const getListRosterInvitesUrl = (
  teamId: string,
  params?: ListRosterInvitesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/teams/${teamId}/invites?${stringifiedParams}`
    : `/api/v1/teams/${teamId}/invites`;
};

export const listRosterInvites = async (
  teamId: string,
  params?: ListRosterInvitesParams,
  options?: RequestInit,
): Promise<PaginatedInvitesResponse> => {
  return customFetch<PaginatedInvitesResponse>(
    getListRosterInvitesUrl(teamId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListRosterInvitesQueryKey = (
  teamId: string,
  params?: ListRosterInvitesParams,
) => {
  return [
    `/api/v1/teams/${teamId}/invites`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListRosterInvitesQueryOptions = <
  TData = Awaited<ReturnType<typeof listRosterInvites>>,
  TError = ErrorType<
    UnauthorizedResponse | ForbiddenResponse | NotFoundResponse
  >,
>(
  teamId: string,
  params?: ListRosterInvitesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listRosterInvites>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListRosterInvitesQueryKey(teamId, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listRosterInvites>>
  > = ({ signal }) =>
    listRosterInvites(teamId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!teamId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listRosterInvites>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

